<template>
  <el-menu style="height: 4vh" :default-active="activePage" mode="horizontal" background-color="#545c64" text-color="#fff" active-text-color="cyan">
    <el-menu-item @click="jump(item.pageSign)" style="height: 4vh" v-for="item in menuList" :key="item.pageSign" :index="item.pageSign">{{
      item.title
    }}</el-menu-item>
  </el-menu>
</template>
<script>
import { getMultiConfig } from '@/api/main';
export default {
  name: 'MainNav',
  data() {
    return {
      menuList: [
        { title: '添加素材', pageSign: 'AddMaterial', categoryId: 9, defaultShow: true },
        { title: '本地素材', pageSign: 'LocalMaterial', categoryId: 9 }
      ],
      activePage: 'AddMaterial' // 当前页面标识
    };
  },
  created() {
    this.getConfig();
  },
  methods: {
    getConfig() {
      let params = {
        codeList: ['sys.menulist']
      };
      // 获取配置信息
      getMultiConfig(params).then((multiConfig) => {
        this.menuList = JSON.parse(multiConfig.data['sys.menulist']) || this.menuList;
        this.activePage = this.menuList.find((item) => item.defaultShow === true).pageSign;
        this.jump(this.activePage);
      });
    },
    jump(val) {
      this.activePage = val;
      let categoryParentId = String(this.menuList.find((item) => item.pageSign === val).categoryId || '');
      let data = { activePage: val, categoryParentId: categoryParentId };
      this.$emit('handleSwitchNav', data);
    }
  }
};
</script>
<style lang="css" scoped>
.el-menu--horizontal {
  display: flex !important;
  justify-content: space-between;
}
.el-menu--horizontal > .el-menu-item {
  height: 4vh;
  line-height: 4vh;
  flex: 1 1 0;
  text-align: center;
  padding: 0;
}
</style>
